from collections import defaultdict, deque

class TaskRegistry:
    def __init__(self):
        self._tasks: dict[str, TaskRecord] = {}

    def add(self, spec: TaskSpec) -> TaskRecord:
        record = TaskRecord.create(spec)
        self._tasks[record.id] = record
        return record

    def get(self, task_id: str) -> Optional[TaskRecord]:
        return self._tasks.get(task_id)

    def update_status(self, task_id: str, status: TaskStatus,
                      result: Any = None, error: str = None) -> None:
        t = self._tasks[task_id]
        t.status = status
        if result is not None:
            t.result = result
        if error is not None:
            t.error = error
        if status == TaskStatus.RUNNING:
            t.started_at = time.time()
            t.attempts += 1
        elif status in (TaskStatus.DONE, TaskStatus.FAILED, TaskStatus.CANCELLED):
            t.finished_at = time.time()

    def ready_tasks(self) -> list[TaskRecord]:
        """Return PENDING tasks whose dependencies are all DONE."""
        ready = []
        for t in self._tasks.values():
            if t.status != TaskStatus.PENDING:
                continue
            deps_done = all(
                self._tasks.get(dep_id, None) is not None
                and self._tasks[dep_id].status == TaskStatus.DONE
                for dep_id in t.spec.depends_on
            )
            if deps_done:
                ready.append(t)
        return sorted(ready, key=lambda t: t.spec.priority)

    def topological_order(self) -> list[str]:
        """Kahn's algorithm — returns task ids in valid execution order."""
        in_degree: dict[str, int] = defaultdict(int)
        dependents: dict[str, list[str]] = defaultdict(list)

        for tid, t in self._tasks.items():
            for dep in t.spec.depends_on:
                in_degree[tid] += 1
                dependents[dep].append(tid)

        queue = deque(tid for tid in self._tasks if in_degree[tid] == 0)
        order = []
        while queue:
            tid = queue.popleft()
            order.append(tid)
            for dependent in dependents[tid]:
                in_degree[dependent] -= 1
                if in_degree[dependent] == 0:
                    queue.append(dependent)

        if len(order) != len(self._tasks):
            raise ValueError("Cycle detected in task dependency graph")
        return order

    def summary(self) -> dict[str, int]:
        counts: dict[str, int] = defaultdict(int)
        for t in self._tasks.values():
            counts[t.status.value] += 1
        return dict(counts)

from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

# ── Executor functions ───────────────────────────────────────────────────────

summarise_chain = (
    ChatPromptTemplate.from_messages([
        ("system", "Summarise the given text in 2-3 sentences."),
        ("human", "{text}"),
    ]) | llm | StrOutputParser()
)

classify_chain = (
    ChatPromptTemplate.from_messages([
        ("system", "Classify the text into one of: {categories}. Reply with just the category name."),
        ("human", "{text}"),
    ]) | llm | StrOutputParser()
)

extract_chain = (
    ChatPromptTemplate.from_messages([
        ("system", "Extract {field} from the following text. Return only the extracted value."),
        ("human", "{text}"),
    ]) | llm | StrOutputParser()
)

def executor_summarise(input_data: dict) -> str:
    return summarise_chain.invoke({"text": input_data["text"]})

def executor_classify(input_data: dict) -> str:
    return classify_chain.invoke({
        "text": input_data["text"],
        "categories": ", ".join(input_data["categories"]),
    })

def executor_extract(input_data: dict) -> str:
    return extract_chain.invoke({
        "text": input_data["text"],
        "field": input_data["field"],
    })

# Registry maps executor name → callable
EXECUTOR_REGISTRY: dict[str, Callable[[dict], str]] = {
    "summarise": executor_summarise,
    "classify": executor_classify,
    "extract": executor_extract,
}

import concurrent.futures
import signal

def run_task(record: TaskRecord, registry: TaskRegistry) -> None:
    """Execute one task with retry logic."""
    executor_fn = EXECUTOR_REGISTRY.get(record.spec.executor)
    if executor_fn is None:
        registry.update_status(record.id, TaskStatus.FAILED,
                                error=f"Unknown executor: {record.spec.executor}")
        return

    registry.update_status(record.id, TaskStatus.RUNNING)
    try:
        result = executor_fn(record.spec.input_data)
        registry.update_status(record.id, TaskStatus.DONE, result=result)
    except Exception as e:
        if record.can_retry():
            # Reset to PENDING for retry
            record.status = TaskStatus.PENDING
            record.error = str(e)
        else:
            registry.update_status(record.id, TaskStatus.FAILED, error=str(e))

def run_all_tasks(registry: TaskRegistry, max_workers: int = 4) -> dict:
    """
    Run all tasks respecting dependency order.
    Uses a thread pool for tasks that can run in parallel.
    """
    max_iterations = len(registry._tasks) * (2 + 1)  # allow for retries
    iteration = 0

    while iteration < max_iterations:
        ready = registry.ready_tasks()
        if not ready:
            # Check if there are still running or pending tasks
            pending_or_running = [
                t for t in registry._tasks.values()
                if t.status in (TaskStatus.PENDING, TaskStatus.RUNNING)
            ]
            if not pending_or_running:
                break
            # Deadlock: pending tasks with unresolvable dependencies
            failed_deps = [
                t for t in pending_or_running
                if any(
                    registry._tasks.get(dep) and
                    registry._tasks[dep].status == TaskStatus.FAILED
                    for dep in t.spec.depends_on
                )
            ]
            for t in failed_deps:
                registry.update_status(t.id, TaskStatus.CANCELLED,
                                       error="Dependency failed")
            if not failed_deps:
                break  # nothing to do
            continue

        with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as pool:
            futures = {pool.submit(run_task, task, registry): task for task in ready}
            concurrent.futures.wait(futures)

        iteration += 1

    return registry.summary()
